import{c as d,Q as t,j as c,m as o}from"./chunks/framework.iD28w_5a.js";const n=JSON.parse('{"title":"Shell","description":"","frontmatter":{},"headers":[],"relativePath":"document/user/shell.md","filePath":"document/user/shell.md","lastUpdated":1777209094000}'),l={name:"document/user/shell.md"};function r(a,e,s,h,i,p){return t(),c("div",null,[...e[0]||(e[0]=[o('<h1 id="shell" tabindex="-1">Shell <a class="header-anchor" href="#shell" aria-label="Permalink to &quot;Shell&quot;">​</a></h1><blockquote><p>里程碑: <code>024_shell</code> <code>027_fs_vfs</code> <code>028b_fs_ext2_write</code> <code>028c_fs_cwd_stat</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>用户态 read-eval-print shell，支持 11 个内置命令和输出重定向。通过系统调用与内核交互，支持文件和目录操作。</p><h2 id="架构-user-programs-shell-main-cpp-user-programs-shell-shell-hpp" tabindex="-1">架构 (<code>user/programs/shell/main.cpp</code>, <code>user/programs/shell/shell.hpp</code>) <a class="header-anchor" href="#架构-user-programs-shell-main-cpp-user-programs-shell-shell-hpp" aria-label="Permalink to &quot;架构 (`user/programs/shell/main.cpp`, `user/programs/shell/shell.hpp`)&quot;">​</a></h2><ol><li><code>print_prompt</code> → 显示提示符</li><li><code>read_line</code> — <code>sys_read(fd, buf, len)</code> 读取输入</li><li><code>tokenize</code> — 按空格切割为 argc/argv</li><li><code>dispatch</code> — 查表执行内置命令</li><li>循环</li></ol><h2 id="内置命令" tabindex="-1">内置命令 <a class="header-anchor" href="#内置命令" aria-label="Permalink to &quot;内置命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>实现</th><th>功能</th></tr></thead><tbody><tr><td><code>echo</code></td><td><code>cmd_echo.cpp</code></td><td>输出文本，支持 <code>&gt; file</code> 重定向</td></tr><tr><td><code>help</code></td><td><code>cmd_help.cpp</code></td><td>打印命令列表</td></tr><tr><td><code>clear</code></td><td><code>cmd_clear.cpp</code></td><td>ANSI 清屏 (<code>\\033[2J\\033[H</code>)</td></tr><tr><td><code>ls</code></td><td><code>cmd_ls.cpp</code></td><td>列出目录 (<code>open→getdents→close</code>)</td></tr><tr><td><code>cat</code></td><td><code>cmd_cat.cpp</code></td><td>显示文件内容 (<code>open→read→write→close</code>)</td></tr><tr><td><code>cd</code></td><td><code>cmd_cd.cpp</code></td><td>切换目录 (<code>sys_chdir</code>)</td></tr><tr><td><code>pwd</code></td><td><code>cmd_pwd.cpp</code></td><td>显示当前目录 (<code>sys_getcwd</code>)</td></tr><tr><td><code>stat</code></td><td><code>cmd_stat.cpp</code></td><td>显示文件元数据</td></tr><tr><td><code>touch</code></td><td><code>cmd_touch.cpp</code></td><td>创建文件 (<code>sys_creat</code>)</td></tr><tr><td><code>mkdir</code></td><td><code>cmd_mkdir.cpp</code></td><td>创建目录 (<code>sys_mkdir</code>)</td></tr><tr><td><code>rm</code></td><td><code>cmd_rm.cpp</code></td><td>删除文件 (<code>sys_unlink</code>)</td></tr><tr><td><code>rmdir</code></td><td><code>cmd_rmdir.cpp</code></td><td>删除目录 (<code>sys_rmdir</code>)</td></tr></tbody></table><h2 id="输出重定向" tabindex="-1">输出重定向 <a class="header-anchor" href="#输出重定向" aria-label="Permalink to &quot;输出重定向&quot;">​</a></h2><ul><li><code>echo hello &gt; /file</code> — 解析 <code>&gt;</code> 符号，<code>sys_open(path, O_WRONLY|O_CREAT)</code> + <code>sys_write</code></li></ul><h2 id="构建" tabindex="-1">构建 <a class="header-anchor" href="#构建" aria-label="Permalink to &quot;构建&quot;">​</a></h2><ul><li>CMake 嵌入 shell ELF 到磁盘镜像</li><li>链接地址 <code>0x400000</code> (<code>user/programs/shell/linker.ld</code>)</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>user/programs/shell/main.cpp</code> — 入口 &amp; 主循环</li><li><code>user/programs/shell/shell.hpp</code> — Shell 类</li><li><code>user/programs/shell/cmd_*.cpp</code> — 各命令实现</li><li><code>user/programs/shell/linker.ld</code> — 链接脚本</li></ul>',14)])])}const _=d(l,[["render",r]]);export{n as __pageData,_ as default};
